-- ----------------------------------------------------------------------------
-- vw_job_boards: Table: JobBoards - Configured job board sources that can be crawled for listings.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_job_boards WITH (security_invoker = ON) AS
SELECT
  t.job_board_id,                                                               -- Primary key for job boards.
  t.name,                                                                       -- Display name of the job board (e.g., ZipRecruiter, Indeed, LinkedIn, WeWorkRemotely).
  t.description,                                                                -- Notes about this board's behavior, rate limits, or special handling requirements.
  t.is_enabled,                                                                 -- Whether this board is active for search runs.
  t.max_pages,                                                                  -- Maximum number of result pages to crawl per search URL. Default is 3.
  t.is_headless,                                                                -- Whether to run the Playwright browser in headless mode for this board.
  t.browser_channel,                                                            -- Optional browser variant to use (e.g., msedge). NULL means default Chromium.
  calc_job_boards_job_listings(t.job_board_id) AS job_listings                  -- Count of job listings scraped from this board.
FROM job_boards t;

-- ----------------------------------------------------------------------------
-- vw_search_urls: Table: SearchUrls - Individual search URLs configured per board, each representing a specific query to crawl.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_search_urls WITH (security_invoker = ON) AS
SELECT
  t.search_url_id,                                                              -- Primary key for search URLs.
  t.name,                                                                       -- Descriptive label for this search query (e.g., 'Staff Engineer - Remote').
  t.job_board,                                                                  -- Which job board this search URL belongs to.
  t.url,                                                                        -- The full search URL to crawl on this board.
  t.is_enabled,                                                                 -- Whether this search URL is active for crawling.
  calc_search_urls_job_board_name(t.search_url_id) AS job_board_name            -- Display name of the parent job board.
FROM search_urls t;

-- ----------------------------------------------------------------------------
-- vw_role_archetypes: Table: RoleArchetypes - Target role descriptions that define ideal job types for semantic matching.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_role_archetypes WITH (security_invoker = ON) AS
SELECT
  t.role_archetype_id,                                                          -- Primary key for role archetypes.
  t.name,                                                                       -- Archetype title (e.g., 'Staff Platform Architect', 'AI Systems Engineer').
  t.description,                                                                -- Natural language description of this ideal role type. Embedded into ChromaDB for archetype scoring.
  t.signals_positive,                                                           -- Comma-separated keywords or phrases indicating strong fit for this archetype.
  t.signals_negative                                                            -- Comma-separated keywords or phrases indicating misfit for this archetype.
FROM role_archetypes t;

-- ----------------------------------------------------------------------------
-- vw_rubric_dimensions: Table: RubricDimensions - Universal evaluation criteria applied to all listings for culture and quality scoring.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rubric_dimensions WITH (security_invoker = ON) AS
SELECT
  t.rubric_dimension_id,                                                        -- Primary key for rubric dimensions.
  t.name,                                                                       -- Dimension name (e.g., 'Role Scope', 'Technical Depth').
  t.description,                                                                -- What this dimension evaluates and why it matters.
  t.signals_positive,                                                           -- Comma-separated positive indicators for this dimension. Embedded into global_positive_signals collection.
  t.signals_negative                                                            -- Comma-separated red flags for this dimension. Embedded into negative_signals collection.
FROM rubric_dimensions t;

-- ----------------------------------------------------------------------------
-- vw_resumes: Table: Resumes - Candidate resumes that anchor the entire RAG scoring pipeline. Every search run scores job listings against a specific resume's embeddings.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_resumes WITH (security_invoker = ON) AS
SELECT
  t.resume_id,                                                                  -- Primary key for resumes.
  t.name,                                                                       -- Display name for this resume version (e.g., 'Platform Engineer - 2026Q1').
  t.description,                                                                -- Notes about what this resume version emphasizes or targets.
  t.file_path,                                                                  -- Path to the resume markdown file relative to project root (e.g., 'data/resume.md').
  t.indexed_at,                                                                 -- When this resume was last chunked and embedded into ChromaDB. NULL means not yet indexed.
  calc_resumes_resume_sections(t.resume_id) AS resume_sections,                 -- Count of sections (## heading chunks) extracted from this resume.
  calc_resumes_search_runs(t.resume_id) AS search_runs                          -- Count of search runs that scored against this resume.
FROM resumes t;

-- ----------------------------------------------------------------------------
-- vw_resume_sections: Table: ResumeSections - Individual chunks of a resume, split by ## headings. Each section is embedded separately into ChromaDB for granular semantic matching against job descriptions.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_resume_sections WITH (security_invoker = ON) AS
SELECT
  t.resume_section_id,                                                          -- Primary key. Slug of the section heading (e.g., 'resume-core-strengths').
  t.name,                                                                       -- Section heading text (e.g., 'Core Strengths', 'Experience').
  t.resume,                                                                     -- Which resume this section belongs to.
  t.section_order,                                                              -- Order of this section within the resume (1-based). Preserves document structure.
  t.content,                                                                    -- Full text of this section including the ## heading and all body content up to the next ## heading. This is the document embedded into ChromaDB.
  t.chroma_doc_id,                                                              -- Document ID in the ChromaDB resume collection (e.g., 'resume-core-strengths'). Used for idempotent upserts.
  calc_resume_sections_resume_name(t.resume_section_id) AS resume_name          -- Display name of the parent resume.
FROM resume_sections t;

-- ----------------------------------------------------------------------------
-- vw_search_runs: Table: SearchRuns - Individual pipeline execution runs that crawl boards, score listings, and produce ranked results. Each run scores against a specific resume.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_search_runs WITH (security_invoker = ON) AS
SELECT
  t.search_run_id,                                                              -- Primary key for search runs.
  t.name,                                                                       -- Human-readable run label (typically date + time).
  t.resume,                                                                     -- Which resume was used for fit_score computation in this run. The central link in the RAG pipeline.
  t.run_date,                                                                   -- When this search run was executed.
  t.archetype_weight,                                                           -- Weight applied to archetype match score (0.0 - 1.0).
  t.fit_weight,                                                                 -- Weight applied to resume fit score (0.0 - 1.0).
  t.history_weight,                                                             -- Weight applied to decision history score (0.0 - 1.0).
  t.comp_weight,                                                                -- Weight applied to compensation alignment score (0.0 - 1.0).
  t.negative_weight,                                                            -- Penalty multiplier for negative signal score (0.0 - 1.0).
  t.culture_weight,                                                             -- Weight applied to culture/quality dimension score (0.0 - 1.0).
  t.base_salary,                                                                -- Target annual salary for compensation scoring. Default $220,000.
  t.min_score_threshold,                                                        -- Minimum final score to include in results (0.0 - 1.0). Default 0.45.
  t.disqualify_on_llm_flag,                                                     -- Whether to run the LLM disqualifier pass on listings.
  t.total_found,                                                                -- Total listings collected from boards in this run.
  t.total_scored,                                                               -- Total listings that passed through the scorer.
  t.total_excluded,                                                             -- Listings filtered below min_score_threshold.
  t.total_deduplicated,                                                         -- Duplicate listings collapsed during this run.
  t.failed_listings,                                                            -- Count of listings that failed scoring.
  calc_search_runs_resume_name(t.search_run_id) AS resume_name,                 -- Display name of the resume used for this run.
  calc_search_runs_score_results(t.search_run_id) AS score_results              -- Count of score results produced in this run.
FROM search_runs t;

-- ----------------------------------------------------------------------------
-- vw_job_listings: Table: JobListings - Individual job postings scraped from job boards, normalized to a common data contract.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_job_listings WITH (security_invoker = ON) AS
SELECT
  t.job_listing_id,                                                             -- Primary key. Composite of board and external ID (e.g., 'ziprecruiter-abc123').
  t.name,                                                                       -- Job title as listed on the board, sanitized for filesystem safety.
  t.job_board,                                                                  -- Which job board this listing was scraped from.
  t.external_id,                                                                -- The job board's unique identifier for this posting.
  t.company,                                                                    -- Company name, sanitized for filesystem safety.
  t.location,                                                                   -- Job location (city, state, remote, hybrid, etc.).
  t.url,                                                                        -- Direct URL link to the job posting on the board.
  t.full_text,                                                                  -- Complete job description text. Max 250,000 characters. Embedded into ChromaDB for scoring.
  t.posted_at,                                                                  -- When the job was posted on the board.
  t.comp_min,                                                                   -- Minimum compensation in USD, parsed from job description.
  t.comp_max,                                                                   -- Maximum compensation in USD, parsed from job description.
  t.comp_source,                                                                -- Source of compensation data: 'employer' (from JD) or 'estimated' (board-generated).
  t.comp_text,                                                                  -- Raw compensation text matched from the job description (e.g., '$180,000 - $220,000/year').
  calc_job_listings_job_board_name(t.job_listing_id) AS job_board_name,         -- Display name of the source job board.
  calc_job_listings_score_results(t.job_listing_id) AS score_results,           -- Number of times this listing has been scored across search runs.
  calc_job_listings_decisions(t.job_listing_id) AS decisions                    -- Number of decisions recorded for this listing.
FROM job_listings t;

-- ----------------------------------------------------------------------------
-- vw_score_results: Table: ScoreResults - Component and final scores for a job listing within a specific search run.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_score_results WITH (security_invoker = ON) AS
SELECT
  t.score_result_id,                                                            -- Primary key for score results.
  calc_score_results_name(t.score_result_id) AS name,                           -- Display label combining job title and search run.
  t.job_listing,                                                                -- The job listing that was scored.
  t.search_run,                                                                 -- The search run during which this score was produced.
  t.fit_score,                                                                  -- Semantic similarity to resume (0.0 - 1.0). Based on cosine distance in resume ChromaDB collection.
  t.archetype_score,                                                            -- Match to role archetypes (0.0 - 1.0). Based on cosine distance in role_archetypes collection.
  t.history_score,                                                              -- Match to past accepted decisions (0.0 - 1.0). Only 'yes' verdicts contribute.
  t.comp_score,                                                                 -- Compensation alignment with base salary (0.0 - 1.0). Non-linear curve; 0.5 when comp is missing.
  t.negative_score,                                                             -- Penalty score from negative signal matches (0.0 - 1.0). Subtracted from positive scores.
  t.culture_score,                                                              -- Match to positive culture/quality dimensions (0.0 - 1.0).
  t.is_disqualified,                                                            -- Whether the LLM disqualifier flagged this listing. If true, final score is forced to 0.0.
  t.disqualifier_reason,                                                        -- Free-text explanation from the LLM disqualifier about why the role was flagged.
  calc_score_results_final_score(t.score_result_id) AS final_score,             -- Weighted fusion of all component scores. Zeroed if disqualified. Formula: max(0, positive_sum - negative_weight * negative_score).
  t.duplicate_boards,                                                           -- Comma-separated list of other boards where this same job appeared (cross-board deduplication).
  calc_score_results_job_listing_name(t.score_result_id) AS job_listing_name,   -- Title of the scored job listing.
  calc_score_results_search_run_name(t.score_result_id) AS search_run_name,     -- Label of the parent search run.
  calc_score_results_company(t.score_result_id) AS company                      -- Company name from the scored listing.
FROM score_results t;

-- ----------------------------------------------------------------------------
-- vw_decisions: Table: Decisions - Operator verdicts on reviewed job listings, used as training signal for future scoring.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_decisions WITH (security_invoker = ON) AS
SELECT
  t.decision_id,                                                                -- Primary key for decisions.
  calc_decisions_name(t.decision_id) AS name,                                   -- Display label combining verdict and job title.
  t.job_listing,                                                                -- The job listing this decision is about.
  t.verdict,                                                                    -- Operator's judgment: 'yes' (interested), 'no' (rejected), 'maybe' (uncertain), or 'removed' (retracted).
  t.reason,                                                                     -- Free-text explanation for the verdict. Stored for audit purposes.
  t.recorded_at,                                                                -- Timestamp when this decision was recorded.
  calc_decisions_is_scoring_signal(t.decision_id) AS is_scoring_signal,         -- Whether this verdict contributes to history_score. Only 'yes' verdicts are scoring signals.
  calc_decisions_job_listing_name(t.decision_id) AS job_listing_name,           -- Title of the decided job listing.
  calc_decisions_company(t.decision_id) AS company,                             -- Company name from the decided listing.
  calc_decisions_board(t.decision_id) AS board                                  -- Job board the decided listing came from.
FROM decisions t;

